import React, { useState } from 'react'
import "./MortgageCalculator.css"

const initialState ={
    amout: '',
    downPayment: '',
    interestRate: '',
    loanTerm: '',
};

const MortgageCalculator = () => {
    const [formData, setFormData] = useState(initialState);
    const [payment, setPayment] = useState(null);
    const [total, setTotal] = useState(null);
    const [interest, setInterest] = useState(null);


    const handleChange = (event) =>{
        const {name, value} = event.target;


        setFormData({
            ...formData,
            [name]:value,
        });
    }

    const handleSubmit = (event)=> {
        event.preventDefault();
        console.log(formData);
        calculateMonthlyPayment();
    };

    calculateMonthlyPayment =() =>{
        const {amout, downPayment, interestRate, loanTerm} = formData;
        const loanAmount = parseFloat(amout) - (downPayment ? parseFloat(downPayment): 0);

        const r =parseFloat(interestRate)/100/12;
        const n = parseFloat(loanTerm) * 12;

        const numerator = loanAmount * r * Math.row(1+r,n);
        const denumerator = Math.row(1+r,n)-1;

        const monthlyPayment = (numerator / denumerator).toFixed(2);
        setPayment(monthlyPayment);

        const totalPayable = (monthlyPayment * n).toFixed(2);
        setTotal(totalPayable);

        const totalInterest = (totalPayable - loanAmount).toFixed(2);
        setInterest(totalInterest); 
    }

  return (
    <div className='mortgage-container'>
        <h2>Mortgage Payment Calculator</h2>
        <form action="" onSubmit={handleSubmit}>

            <div className="form-group">
                <label htmlFor=""> Home Price ($):</label>
                <input type="number"
                        name="amount"
                        value = {formData.amount}
                        onChange={handleChange}
                        required />
            </div>

            <div className="form-group">
                <label htmlFor=""> Down Payment ($):</label>
                <input type="number"
                        name="downPayment"
                        value = {formData.downPayment}
                        onChange={handleChange}
                        required />
            </div>

            <div className="form-group">
                <label htmlFor=""> Interest Rate (%):</label>
                <input type="number"
                        name="interestRate"
                        value = {formData.interestRate}
                        onChange={handleChange}
                        required />
            </div>

            <div className="form-group">
                <label htmlFor=""> loanTerm (years):</label>
                <input type="number"
                        name="loanTerm"
                        value = {formData.loanTerm}
                        onChange={handleChange}
                        required />
            </div>

        </form>
    </div>
  )
}

export default MortgageCalculator
